<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#E06C75">body</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF">&gt;</span></span>
