<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#E06C75">line</span><span style="--shiki-light:#6F42C1;--shiki-dark:#D19A66"> x1</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF">=</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379">"0"</span><span style="--shiki-light:#6F42C1;--shiki-dark:#D19A66"> y1</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF">=</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379">"0"</span><span style="--shiki-light:#6F42C1;--shiki-dark:#D19A66"> x2</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF">=</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379">"200"</span><span style="--shiki-light:#6F42C1;--shiki-dark:#D19A66"> y2</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF">=</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379">"200"</span></span>
